DROP TABLE IF EXISTS `aid_ai_model_func_config`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `aid_ai_model_func_config` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `func_name` varchar(100) NOT NULL COMMENT '功能名称',
  `func_code` varchar(100) NOT NULL COMMENT '功能编码，唯一',
  `model_type` varchar(32) DEFAULT NULL COMMENT '模型大类：text/image/video/audio',
  `generate_mode` varchar(32) DEFAULT NULL COMMENT '生成模式：如 image_edit/image_upscale/text_to_image',
  `model_ids` json NOT NULL COMMENT '可选模型ID列表JSON数组，如 [1,2,3]',
  `status` char(1) NOT NULL DEFAULT '0' COMMENT '状态：0启用 1停用',
  `remark` varchar(500) DEFAULT NULL COMMENT '备注',
  `create_by` varchar(64) DEFAULT '' COMMENT '创建者',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) DEFAULT '' COMMENT '更新者',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `del_flag` char(1) NOT NULL DEFAULT '0' COMMENT '删除标记：0存在 2删除',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_func_code` (`func_code`) USING BTREE,
  KEY `idx_status_del_flag` (`status`,`del_flag`) USING BTREE,
  KEY `idx_model_type` (`model_type`) USING BTREE,
  KEY `idx_generate_mode` (`generate_mode`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=34 DEFAULT CHARSET=utf8mb4 COMMENT='AI模型功能配置表';
/*!40101 SET character_set_client = @saved_cs_client */;

