--
-- Table structure for table `aid_ai_provider`
--

DROP TABLE IF EXISTS `aid_ai_provider`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `aid_ai_provider` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `provider_name` varchar(100) NOT NULL COMMENT '服务商展示名称 (如: 字节火山引擎, OpenAI)',
  `provider_code` varchar(50) NOT NULL COMMENT '服务商唯一编码 (系统内路由标识, 如: bytedance)',
  `logo_url` varchar(500) DEFAULT NULL COMMENT '服务商LOGO图标URL（厂家品牌图标，所属模型共用）',
  `base_url` varchar(500) NOT NULL COMMENT '官方默认API网关地址',
  `api_key` varchar(500) NOT NULL COMMENT '官方默认API秘钥 (加密存储)',
  `api_secret` varchar(500) DEFAULT NULL COMMENT '官方扩展秘钥 (如需)',
  `auth_header` varchar(64) DEFAULT 'Authorization' COMMENT '鉴权 header 名（默认 Authorization，Azure 用 api-key）',
  `auth_prefix` varchar(32) DEFAULT 'Bearer ' COMMENT '鉴权前缀（默认 Bearer，部分厂商无前缀）',
  `extra_headers` json DEFAULT NULL COMMENT '自定义 header（JSON 对象，如 {"api-version":"2024-02-01"}）',
  `extra_body` json DEFAULT NULL COMMENT '请求体附加参数（JSON 对象，如思考模式：{"thinking":{"type":"disabled"}}）',
  `extra_query` json DEFAULT NULL COMMENT '自定义 query string（JSON 对象，百度千帆等需要）',
  `api_key_apply_url` varchar(512) DEFAULT NULL COMMENT 'API Key 申请页直链',
  `official_doc_url` varchar(512) DEFAULT NULL COMMENT '官方接口文档首页',
  `official_price_url` varchar(512) DEFAULT NULL COMMENT '官方定价页直链（后台配价一键核对）',
  `task_query_suffix` varchar(500) DEFAULT NULL COMMENT '任务查询路径模板（%s 为 taskId 占位符），用于异步任务轮询',
  `status` char(1) DEFAULT '0' COMMENT '渠道状态 (0正常 1停用)',
  `del_flag` char(1) DEFAULT '0' COMMENT '删除标志 (0存在 1删除)',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `create_by` varchar(64) DEFAULT '' COMMENT '创建者',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `update_by` varchar(64) DEFAULT '' COMMENT '更新者',
  `remark` varchar(500) DEFAULT NULL COMMENT '备注',
  `supports_callback` tinyint(1) DEFAULT '0' COMMENT '是否支持回调通知',
  `schedule_strategy_json` text COMMENT '默认调度策略JSON',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_provider_code` (`provider_code`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=21 DEFAULT CHARSET=utf8mb4 COMMENT='AI服务商';
/*!40101 SET character_set_client = @saved_cs_client */;

