--
-- Table structure for table `aid_ai_voice_library`
--

DROP TABLE IF EXISTS `aid_ai_voice_library`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `aid_ai_voice_library` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `provider_id` bigint(20) DEFAULT NULL COMMENT '所属服务商ID（冗余自 aid_ai_model.provider_id）',
  `model_id` bigint(20) NOT NULL COMMENT '所属AI模型ID（主归属，关联 aid_ai_model.id）',
  `voice_code` varchar(128) NOT NULL COMMENT '厂商侧真实 voice_id / 音色编码',
  `voice_name` varchar(100) NOT NULL COMMENT '展示名称',
  `avatar_url` varchar(500) DEFAULT NULL COMMENT '头像图URL',
  `avatar_prompt` varchar(100) DEFAULT NULL COMMENT '头像提示',
  `sample_url` varchar(500) DEFAULT NULL COMMENT '试听音频URL',
  `sample_text` varchar(500) DEFAULT NULL COMMENT '试听文案',
  `language` varchar(16) DEFAULT NULL COMMENT '语言区域码：zh-CN / en-US / ja-JP',
  `gender` varchar(16) DEFAULT NULL COMMENT '性别：female / male / neutral',
  `age_range` varchar(16) DEFAULT NULL COMMENT '年龄段：child/teen/young/adult/middle/elderly',
  `character_types` json DEFAULT NULL COMMENT '角色类型 tag_code JSON 数组',
  `voice_styles` json DEFAULT NULL COMMENT '使用场景 tag_code JSON 数组',
  `tone_tags` json DEFAULT NULL COMMENT '音调 tag_code JSON 数组',
  `emotion_tags` json DEFAULT NULL COMMENT '擅长情感编码 JSON 数组（来源 aid_config.voice_emotion）',
  `supports_emotion` tinyint(1) DEFAULT '0' COMMENT '是否支持情感参数',
  `supports_speed` tinyint(1) DEFAULT '0' COMMENT '是否支持语速参数',
  `supports_pitch` tinyint(1) DEFAULT '0' COMMENT '是否支持音调参数',
  `default_speed` decimal(4,1) DEFAULT '1.0' COMMENT '默认语速（0.5 ~ 2.0）',
  `default_pitch` decimal(4,1) DEFAULT '0.0' COMMENT '默认音调（-12 ~ 12）',
  `sample_rate` int(11) DEFAULT NULL COMMENT '采样率，示例 16000/24000/48000',
  `audio_format` varchar(16) DEFAULT NULL COMMENT '音频格式：mp3/wav/pcm',
  `offline_time` datetime NOT NULL DEFAULT '9999-12-31 00:00:00' COMMENT '下架时间(9999-12-31表示永不下架)',
  `sort_order` int(11) NOT NULL DEFAULT '0' COMMENT '排序（越大越靠前）',
  `status` char(1) NOT NULL DEFAULT '0' COMMENT '状态：0启用 1停用',
  `remark` varchar(500) DEFAULT NULL COMMENT '备注',
  `del_flag` char(1) NOT NULL DEFAULT '0' COMMENT '删除标志：0存在 2删除',
  `create_by` varchar(64) DEFAULT '' COMMENT '创建者',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) DEFAULT '' COMMENT '更新者',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_model_voice` (`model_id`,`voice_code`) USING BTREE,
  KEY `idx_status_del_flag` (`status`,`del_flag`) USING BTREE,
  KEY `idx_status_del_offline` (`status`,`del_flag`,`offline_time`) USING BTREE,
  KEY `idx_provider_model` (`provider_id`,`model_id`) USING BTREE,
  KEY `idx_language_gender_age` (`language`,`gender`,`age_range`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=2021 DEFAULT CHARSET=utf8mb4 COMMENT='AI音色库';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `aid_ai_voice_library`
--

LOCK TABLES `aid_ai_voice_library` WRITE;
/*!40000 ALTER TABLE `aid_ai_voice_library` DISABLE KEYS */;
