--
-- Table structure for table `aid_audio_asset`
--

DROP TABLE IF EXISTS `aid_audio_asset`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `aid_audio_asset` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` bigint(20) NOT NULL COMMENT '归属用户ID',
  `project_id` bigint(20) DEFAULT NULL COMMENT '项目ID（可空，项目级音频不绑）',
  `episode_id` bigint(20) DEFAULT NULL COMMENT '剧集ID（可空）',
  `storyboard_id` bigint(20) DEFAULT NULL COMMENT '分镜ID（可空）',
  `audio_record_id` bigint(20) DEFAULT NULL COMMENT '来源 aid_audio_record.id（唯一）',
  `media_task_id` bigint(20) DEFAULT NULL COMMENT '来源 aid_media_task.id',
  `audio_url` varchar(500) NOT NULL COMMENT '音频 OSS 相对路径（@MediaUrl 拼域名）',
  `file_size` bigint(20) DEFAULT NULL COMMENT '文件大小（字节）',
  `audio_format` varchar(16) DEFAULT NULL COMMENT '音频格式：mp3 / wav / pcm',
  `sample_rate` int(11) DEFAULT NULL COMMENT '采样率（16000/24000/48000）',
  `tts_text` text COMMENT '配音文字',
  `voice_library_id` bigint(20) DEFAULT NULL COMMENT '音色库ID（aid_ai_voice_library.id）',
  `voice_model_id` bigint(20) DEFAULT NULL COMMENT '配音模型ID',
  `voice_code` varchar(128) DEFAULT NULL COMMENT '厂商音色编码（voice_id）',
  `voice_name` varchar(100) DEFAULT NULL COMMENT '音色展示名',
  `emotion` varchar(32) DEFAULT NULL COMMENT '情感（happy / sad ...）',
  `speech_rate` int(11) DEFAULT NULL COMMENT '语速',
  `loudness_rate` int(11) DEFAULT NULL COMMENT '音量',
  `pitch` int(11) DEFAULT NULL COMMENT '音调',
  `audio_source` tinyint(4) NOT NULL DEFAULT '1' COMMENT '来源（1:AI生成 2:用户上传）',
  `asset_title` varchar(200) DEFAULT NULL COMMENT '资产标题（默认取 tts_text 截断）',
  `remark` varchar(500) DEFAULT NULL COMMENT '备注',
  `del_flag` char(1) NOT NULL DEFAULT '0' COMMENT '删除标志（0:正常 2:删除）',
  `create_by` varchar(64) DEFAULT '' COMMENT '创建者',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) DEFAULT '' COMMENT '更新者',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_audio_task` (`audio_record_id`) USING BTREE,
  KEY `idx_user_project` (`user_id`,`project_id`,`create_time`) USING BTREE,
  KEY `idx_user_episode` (`user_id`,`episode_id`,`create_time`) USING BTREE,
  KEY `idx_storyboard` (`storyboard_id`) USING BTREE,
  KEY `idx_voice_library` (`voice_library_id`) USING BTREE,
  KEY `idx_media_task` (`media_task_id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=36 DEFAULT CHARSET=utf8mb4 COMMENT='音频资产';
/*!40101 SET character_set_client = @saved_cs_client */;

