-- Table structure for table `aid_audio_record`
--

DROP TABLE IF EXISTS `aid_audio_record`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `aid_audio_record` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` bigint(20) NOT NULL COMMENT '所属用户ID',
  `project_id` bigint(20) DEFAULT NULL COMMENT '所属项目ID（与 aid_media_task 对齐）',
  `episode_id` bigint(20) DEFAULT NULL COMMENT '所属剧集ID（电影模式为0）',
  `storyboard_id` bigint(20) NOT NULL COMMENT '所属分镜ID（aid_storyboard.id）',
  `audio_source` tinyint(4) NOT NULL COMMENT '音频来源：1=AI文字配音(TTS)，2=用户上传',
  `tts_text` text COMMENT 'TTS 待合成文本（audio_source=1 时使用）',
  `voice_model_id` bigint(20) DEFAULT NULL COMMENT 'TTS 模型ID（关联 aid_ai_model.id）',
  `voice_library_id` bigint(20) DEFAULT NULL COMMENT '音色库ID（关联 aid_ai_voice_library.id）',
  `timbre_code` varchar(50) DEFAULT NULL COMMENT '厂商侧音色编码',
  `audio_url` varchar(500) DEFAULT NULL COMMENT '配音文件 OSS URL（TTS 成功且 OSS 已就绪后回填，或用户上传后直接落库）',
  `duration_ms` int(11) DEFAULT NULL COMMENT '音频时长（毫秒）',
  `enable_lip_sync` tinyint(4) DEFAULT '0' COMMENT '是否对口型：0=否，1=是',
  `sync_video_url` varchar(500) DEFAULT NULL COMMENT '对口型视频 OSS URL（enable_lip_sync=1 且对口型任务成功后回填）',
  `tts_media_task_id` bigint(20) DEFAULT NULL COMMENT 'TTS 媒体任务ID（关联 aid_media_task.id），audio_source=1 时填充',
  `sync_media_task_id` bigint(20) DEFAULT NULL COMMENT '对口型媒体任务ID（关联 aid_media_task.id），enable_lip_sync=1 时填充',
  `status` varchar(32) NOT NULL DEFAULT 'PROCESSING' COMMENT '配音状态(PROCESSING处理中 SUCCEEDED成功 FAILED失败, OSS就绪后才置成功)',
  `error_message` varchar(255) DEFAULT NULL COMMENT '失败短文案（≤6 字，给用户看）',
  `del_flag` char(1) DEFAULT '0' COMMENT '删除标志（0=存在 1=已删除）',
  `create_by` varchar(64) DEFAULT '' COMMENT '创建者',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) DEFAULT '' COMMENT '更新者',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `remark` varchar(500) DEFAULT NULL COMMENT '备注',
  `compose_batch_id` varchar(64) DEFAULT NULL COMMENT '合成批次号',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `idx_storyboard_id` (`storyboard_id`) USING BTREE,
  KEY `idx_user_project` (`user_id`,`project_id`,`episode_id`) USING BTREE,
  KEY `idx_tts_task` (`tts_media_task_id`) USING BTREE,
  KEY `idx_sync_task` (`sync_media_task_id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=56 DEFAULT CHARSET=utf8mb4 COMMENT='配音记录';
/*!40101 SET character_set_client = @saved_cs_client */;

