/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `aid_comic_asset` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `asset_type` varchar(20) NOT NULL COMMENT '类型: scene场景, character角色, prop道具',
  `asset_name` varchar(100) NOT NULL COMMENT '资产名称',
  `personality_desc` text COMMENT '性格/特征描述(用于生成约束)',
  `prompt_text` varchar(1000) DEFAULT NULL COMMENT '提示词',
  `image_url` varchar(500) DEFAULT NULL COMMENT '主图',
  `del_flag` char(1) DEFAULT '0',
  `create_time` datetime DEFAULT NULL,
  `create_by` varchar(64) DEFAULT '',
  `update_time` datetime DEFAULT NULL,
  `update_by` varchar(64) DEFAULT '',
  `remark` varchar(500) DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  KEY `idx_asset_type` (`asset_type`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=307 DEFAULT CHARSET=utf8mb4 COMMENT='官方漫画资产表';
/*!40101 SET character_set_client = @saved_cs_client */;

