DROP TABLE IF EXISTS `aid_comic_audit_record`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `aid_comic_audit_record` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `target_type` varchar(20) NOT NULL COMMENT '审核对象类型(project项目 episode剧集)',
  `target_id` bigint(20) NOT NULL COMMENT '审核对象ID(项目ID或剧集ID)',
  `owner_user_id` bigint(20) DEFAULT NULL COMMENT '作品所属用户ID',
  `action` tinyint(4) NOT NULL COMMENT '审核动作(1提交审核 2审核通过 3审核驳回)',
  `before_status` tinyint(4) DEFAULT NULL COMMENT '变更前状态',
  `after_status` tinyint(4) DEFAULT NULL COMMENT '变更后状态',
  `audit_reason` varchar(500) DEFAULT NULL COMMENT '审核意见/驳回原因',
  `operator` varchar(64) DEFAULT NULL COMMENT '操作人(C端为用户标识, 后台为管理员账号)',
  `del_flag` char(1) DEFAULT '0' COMMENT '删除标志(0存在 1删除)',
  `create_by` varchar(64) DEFAULT '' COMMENT '创建者',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) DEFAULT '' COMMENT '更新者',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `remark` varchar(500) DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `idx_target` (`target_type`,`target_id`) USING BTREE,
  KEY `idx_owner` (`owner_user_id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=10 DEFAULT CHARSET=utf8mb4 COMMENT='作品审核记录表';
