--
-- Table structure for table `aid_episode_editor`
--

DROP TABLE IF EXISTS `aid_episode_editor`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `aid_episode_editor` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `project_id` bigint(20) NOT NULL COMMENT '所属项目ID (关联 aid_comic_project.id)',
  `episode_id` bigint(20) NOT NULL COMMENT '所属剧集ID (关联 aid_comic_episode.id)',
  `user_id` bigint(20) NOT NULL COMMENT '最后修改该记录的用户ID',
  `timeline_json` longtext COMMENT '剪辑器工程配置JSON(轨道/素材/特效等)',
  `final_video_url` varchar(1000) DEFAULT NULL COMMENT '成片OSS地址(导出成功后回填)',
  `pending_video_url` varchar(500) DEFAULT NULL COMMENT '待审核成片地址(过审后转正到final_video_url)',
  `cover_url` varchar(500) DEFAULT NULL COMMENT '最新成片的预览封面图OSS地址',
  `export_status` tinyint(4) NOT NULL DEFAULT '0' COMMENT '导出状态(0未导出 1合成中 2成功 3失败)',
  `export_progress` tinyint(4) DEFAULT '0' COMMENT '导出进度百分比(0-100)',
  `export_task_id` varchar(100) DEFAULT NULL COMMENT '导出任务ID(防重复合成)',
  `error_msg` varchar(1000) DEFAULT NULL COMMENT '导出失败原因',
  `export_fingerprint` varchar(64) DEFAULT NULL COMMENT '最近一次导出的素材指纹(SHA-256)，同素材重复导出直接复用成片',
  `del_flag` char(1) DEFAULT '0' COMMENT '删除标志 (0正常 1删除)',
  `create_time` datetime DEFAULT NULL COMMENT '首次进入编辑器初始化的时间',
  `create_by` varchar(64) DEFAULT '' COMMENT '创建者',
  `update_time` datetime DEFAULT NULL COMMENT '最后一次保存草稿或状态变更的时间',
  `update_by` varchar(64) DEFAULT '' COMMENT '更新者',
  `remark` varchar(500) DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_project_episode` (`project_id`,`episode_id`) USING BTREE COMMENT '强约束：同一项目的同一剧集(电影为episode_id=0)只有一条剪辑记录'
) ENGINE=InnoDB AUTO_INCREMENT=27 DEFAULT CHARSET=utf8mb4 COMMENT='剧集剪辑';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `aid_episode_editor`
