  `occurrence_count` int(11) DEFAULT '1' COMMENT '相同 hash 累计次数',
  `sample_hash` char(32) DEFAULT NULL COMMENT 'raw_message 归一化 MD5',
  `first_seen` datetime DEFAULT NULL COMMENT '首次出现时间',
  `last_seen` datetime DEFAULT NULL COMMENT '最近出现时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_provider_hash` (`provider_code`,`sample_hash`) USING BTREE,
  KEY `idx_unmatched` (`matched_rule_id`,`last_seen`) USING BTREE,
  KEY `idx_last_seen` (`last_seen`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=1219 DEFAULT CHARSET=utf8mb4 COMMENT='错误日志';
