  `billing_status` varchar(20) DEFAULT 'INIT' COMMENT '计费状态: INIT/FROZEN/SUCCESS/FAILED',
  `frozen_amount` decimal(10,2) DEFAULT NULL COMMENT '预冻结金额（元）',
  `billing_trace_id` varchar(64) DEFAULT NULL COMMENT '计费追踪ID（幂等）',
  `billing_snapshot_json` text COMMENT '计费快照JSON（SKU定价+token估值，用于差额结算）',
  `actual_cost` decimal(12,6) DEFAULT NULL COMMENT '实际扣费金额（结算后更新）',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `idx_project_user` (`project_id`,`user_id`) USING BTREE,
  KEY `idx_reclaim_scan` (`del_flag`,`status`,`task_type`) USING BTREE,
  KEY `idx_create_model` (`create_time`,`model_code`) USING BTREE,
  KEY `idx_billing_scan` (`billing_status`,`update_time`) USING BTREE
