DROP TABLE IF EXISTS `aid_gen_record`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `aid_gen_record` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `user_id` bigint(20) NOT NULL,
  `project_id` bigint(20) DEFAULT NULL COMMENT '项目ID(冗余)',
  `episode_id` bigint(20) DEFAULT NULL COMMENT '剧集ID(电影为0, 冗余)',
  `storyboard_id` bigint(20) NOT NULL,
  `gen_type` varchar(20) NOT NULL COMMENT '生成类型(image单图 grid宫格 i2v图生 multi多参 edge首尾 upload_video上传 compose合成)',
  `file_url` varchar(500) NOT NULL COMMENT '生成的URL',
  `task_id` varchar(100) DEFAULT NULL COMMENT '大模型异步任务ID(用于回调接口匹配)',
  `status` tinyint(4) DEFAULT '0' COMMENT '生成状态(0处理中, 1成功, 2失败)',
  `gen_params` json DEFAULT NULL COMMENT '生成参数JSON(无参场景为空)',
  `biz_seq` bigint(20) DEFAULT NULL COMMENT '业务序号(父任务ID*1000000+槽位, 分镜出图/出片幂等键)',
  `prompt_text` text COMMENT '最终生成提示词',
  `model_id` bigint(20) DEFAULT NULL COMMENT '关联的aid_ai_model（用户上传等无模型场景为空）',
  `user_input_text` text COMMENT '用户自己输入的补充文本',
  `base_image_id` bigint(20) DEFAULT NULL COMMENT '图生视频依赖的底图',
  `first_image_id` bigint(20) DEFAULT NULL COMMENT '首尾帧视频依赖的首图',
  `last_image_id` bigint(20) DEFAULT NULL COMMENT '首尾帧视频依赖的尾图',
  `video_duration` int(11) DEFAULT NULL COMMENT '视频时长',
  `sound_desc` varchar(255) DEFAULT NULL COMMENT '音效描述',
  `cost_credits` decimal(10,2) DEFAULT '0.00' COMMENT '消耗积分',
  `is_selected` tinyint(4) DEFAULT '0' COMMENT '是否被选为最终分镜(0否 1是)',
  `del_flag` char(1) DEFAULT '0',
  `create_time` datetime DEFAULT NULL,
  `create_by` varchar(64) DEFAULT '',
  `update_time` datetime DEFAULT NULL,
  `update_by` varchar(64) DEFAULT '',
  `remark` varchar(500) DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_gen_record_biz_seq` (`biz_seq`) USING BTREE,
  KEY `idx_storyboard` (`storyboard_id`) USING BTREE,
  KEY `idx_task_id` (`task_id`) USING BTREE,
  KEY `idx_proj_ep_user_type` (`project_id`,`episode_id`,`user_id`,`gen_type`,`del_flag`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=507 DEFAULT CHARSET=utf8mb4 COMMENT='生成记录';
