  KEY `idx_billing_scan` (`billing_status`,`update_time`) USING BTREE,
  KEY `idx_oss_compensate` (`oss_pending`,`update_time`,`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=2079016480620101635 DEFAULT CHARSET=utf8mb4 COMMENT='媒体任务表';
