INSERT INTO `aid_prompt_lib` VALUES (77,0,'subject','三分构图','rule of thirds composition, golden ratio, balanced visual harmony',NULL,NULL,NULL,1,'0','0','2026-03-31 22:17:30','system','2026-05-15 12:33:55','system',NULL),(78,0,'composition','对称构图','绝对对称构图画面左右完美对称，花田以人物为中轴线左右分布完全相同左侧野花颜色密度与右侧一一对应天空云朵恰好对称，人物站在绝对正中央身体正直左右完全对称，黄金时刻逆光形成对称光环，完美秩序中的超现实治愈美感，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/3_01对称.jpg',2,'0','0','2026-03-31 22:17:30','system','2026-03-31 22:17:30','system',NULL),(79,0,'composition','中心构图','中心构图人物绝对居中形成完美垂直中轴线，人物站在野花草甸正中央，鼻梁下巴锁骨窝全部在中轴线上，花田向两侧对称展开天空在头顶对称分布，黄金时刻逆光形成对称光晕，力量与仪式感的治愈，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/2_06中心构图.jpg',3,'0','0','2026-03-31 22:17:30','system','2026-03-31 22:17:30','system',NULL),(80,0,'composition','引导线法','引导线构图野花排列形成的自然蜿蜒线条从画面左下角延伸至人物脚下再延伸到远方林带，视线被引导线牵引走向人物，人物站在引导线的终点处，三十五毫米广角强化纵深透视，黄金时刻暖光从引导线方向斜照，所有路都通向人物的治愈感，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/2_08引导线.jpg',4,'0','0','2026-03-31 22:17:30','system','2026-03-31 22:17:30','system',NULL),(81,0,'composition','框架构图','框架构图画面中的画框，前景树枝和高大野花在上方和左右形成不规则天然框架被浅景深虚化为柔和深绿边框，框内是明亮的人物站在野花田中，黄金时刻暖光照亮框中人物，窥见美好的秘密感，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/2_09框架构图.jpg',5,'0','0','2026-03-31 22:17:30','system','2026-03-31 22:17:30','system',NULL),(82,0,'composition','前景层','前景层构图画面分前中后三层，前景是大幅虚化的粉色紫色野花形成柔和光斑如一层纱，中景是人物的面部和上半身清晰对焦表情温柔，后景是虚化的花田和蓝天，八十五毫米镜头大光圈浅景深，黄金时刻暖光，隔着花丛看人物的层次美感和画意，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/3_04 前景层.jpg',6,'0','0','2026-03-31 22:17:30','system','2026-03-31 22:17:30','system',NULL),(83,0,'composition','对角构图','对角线构图野花草甸沿从左下到右上的对角线倾斜，人物站在对角线中段身体微倾与花田同向，野花色彩沿对角线渐变左下粉紫中段黄白右上蓝绿，画面有强烈的方向动势，黄金时刻侧光打亮对角线，不平衡中的诗意张力，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/2_07对角线.jpg',7,'0','0','2026-03-31 22:17:30','system','2026-03-31 22:17:30','system',NULL),(84,0,'composition','三角构图','三分法构图人物置于画面右三分之一与下三分之一交点面部落在黄金交点上，人物站在野花草甸中，左侧大片花田留白作为负空间上方蓝天占三分之一，画面饱满但不拥挤，黄金时刻暖光，视觉最舒适的平衡感，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/2_05三分法.jpg',8,'0','0','2026-03-31 22:17:30','system','2026-03-31 22:17:30','system',NULL),(85,0,'shot_size','远景','远景，平角度眼平视角，四分之三正面，人物全身立于花田中，人物占画面高度三分之一，天空留白占上半部，黄金时刻暖光从右后方逆光倾泻，肩部呈现金色轮廓光，整个人被薄薄光晕包裹，暖橙阳光与冷蓝天空形成对比，前景野花轻微虚化，中等景深，三分法构图天空留白形成负空间，治愈宁静氛围，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/远景.png',1,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(86,0,'shot_size','全景','全景，正面直视镜头，平角度眼平视角，人物居中站立全身刚好填满画框，双臂自然垂落，面带微笑，浅景深人物全身清晰背景花田和林带明显虚化，黄金时刻正面主光四十五度左上自然日光加柔和辅光，暖调中间调光比约二比一，中心构图，治愈自信沉静氛围，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/全景.png',2,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(87,0,'shot_size','中景','中景，四分之三正面，平角度眼平视角，人物腰部以上构图站在洒满阳光的野花草甸中，面部微微右转目光望向远方林带，表情恬淡若有所思嘴角轻扬，八十五毫米镜头，浅景深背景奶油虚化，温暖漫射黄金时刻光线，辅光比约二比一，右前景有粉色花丛虚化光斑，三分法构图，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/中景.png',3,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(88,0,'shot_size','中近景','中近景，四分之三正面，平角度眼平视角，人物胸口以上构图，边缘有黄金时刻金色轮廓光，肤色透暖粉如瓷器质感，下颌线精致脖颈线条优美，下巴微抬像在呼吸花田空气，眼神明亮瞳孔中有清晰的眼神光反射，嘴唇自然淡粉带着发自内心的微笑，一百毫米镜头，极浅景深，柔和漫射暖调黄金时刻光线，高调光比约一点五比一，背景完全融化在黄绿蓝的虚化光斑中，前景有虚化花朵光点，温暖治愈氛围，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/中近景.png',4,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(89,0,'shot_size','近景','近景，近乎正面视角视线向下约十五度落在花上，平角度眼平视角，人物肩部以上构图，面庞边缘有金色轮廓光，五官精致秀美鼻梁秀挺下颌线优美，肤色呈奶油质感带暖粉色调，眼神向下注视野花表情温柔带着若有若无的微笑，嘴唇自然裸粉色，深棕色瞳孔中有天空和阳光的双重眼神光反射，一百三十五毫米长焦，超浅景深只有面部绝对清晰耳朵轻微柔化，柔和漫射正面日光，下巴下方有微弱反射补光，背景为黄绿蓝粉的多彩虚化光斑，高调暖调，中心构图，亲密治愈氛围，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/近景.png',5,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(91,0,'shot_size','大特写','大特写，全脸从额头到下巴填满整个画面，严格正面平角度眼平视角，人物的面孔，每一缕发丝边缘都被黄金时刻逆光勾勒出发光轮廓，肤色无瑕奶白色偏暖粉面颊有隐约暖色红晕，眼睛是绝对视觉焦点极其锐利瞳孔中有明亮清晰的眼神光，深棕色虹膜中有金色光线反射，睫毛上翘在光线下半透明，眉毛自然根根分明，嘴唇柔和玫瑰粉色带自然光泽，秀美鼻梁形成画面中轴线，超浅景深眼睛绝对锐利耳朵轻微柔化，二百毫米长焦，背景完全虚化为温暖金色光斑，高调柔和漫射光线均匀包裹面部，电影级人像质感，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/大特写.png',7,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(93,0,'camera_angle','平视','平角度眼平视角与被摄者眼睛同高，人物正对镜头站在野花草甸中，眼神平和与观众对视表情松弛带浅浅微笑，五十毫米镜头浅景深，黄金时刻柔和正面光，客观自然的治愈氛围，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/1_03平角度 : 眼平.jpg',1,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(96,0,'camera_angle','鸟瞰','鸟瞰视角正上方垂直向下俯拍，人物站在野花草甸中，头发从头顶放射状散开，四周野花环绕如天然花环，阳光从侧上方投下将人影压缩为一小团阴影，广角镜头深景深，温暖治愈中带宿命感，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/1_01鸟瞰.jpg',4,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(97,0,'camera_angle','虫视角','虫视贴地极端仰拍，前景是巨大虚化的野花花瓣和草叶，透过花丛缝隙看到人物站在上方，大腿和小腿清晰，天空占画面绝大部分，超广角极大透视变形，黄金时刻逆光穿透花瓣，诗意超现实感，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/1_05 虫视.jpg',5,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(99,0,'camera_angle','第一人称视角','主观视角第一人称模拟观看者眼睛所见有轻微自然呼吸晃动感，人物正对镜头微笑仿佛正看着你，眼神温柔直视镜头瞳孔中有你的倒影，画面中一只伸出的手入画即将触碰人物的手指，五十毫米镜头浅景深焦点在眼睛，黄金时刻暖光，最强烈的亲密与沉浸感，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/1_07主观视角 : 第一人称.jpg',7,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(100,0,'camera_angle','荷兰角','荷兰角斜角构图水平轴倾斜约十五度，花田地平线不再水平而是倾斜形成不安对角线，人物站在倾斜的野花草甸中依然美丽但世界正在失衡，蓝天和花田的倾斜对比制造隐藏不安，黄金时刻暖光与倾斜构图形成甜美与不安的矛盾，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/1_08 荷兰角 : 斜角.jpg',8,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(101,0,'camera_angle','侧面视角','侧面剪影九十度侧面逆光拍摄，人物站在野花草甸中侧面朝向镜头，头发在逆光下每缕半透明泛金，衣服边缘发光，面部细节消失仅剩优雅轮廓线条——从额头鼻梁嘴唇下颌到锁骨的完美剪影曲线，背景是金色天空和花田，神秘诗意距离感，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/2_02侧面 : 剪影.jpg',9,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(103,0,'focal_length','14mm 超广角','14mm ultra wide-angle lens, extreme perspective distortion, vast field of view',NULL,NULL,NULL,1,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(104,0,'focal_length','24mm 广角','24mm wide-angle lens, broad field of view, slight perspective exaggeration',NULL,NULL,NULL,2,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(105,0,'focal_length','35mm 小广角','35mm lens, natural wide perspective, classic street photography look',NULL,NULL,NULL,3,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(106,0,'focal_length','50mm 标准','50mm standard lens, natural perspective closest to human eye, no distortion',NULL,NULL,NULL,4,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(107,0,'focal_length','85mm 人像','85mm portrait lens, beautiful background blur, flattering facial proportions',NULL,NULL,NULL,5,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(108,0,'focal_length','105mm 中长焦','105mm medium telephoto, compressed perspective, smooth bokeh, portrait detail',NULL,NULL,NULL,6,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(109,0,'focal_length','135mm 长焦','135mm telephoto lens, strong background compression, creamy bokeh',NULL,NULL,NULL,7,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(110,0,'focal_length','200mm 远摄','200mm telephoto, extreme background compression, isolates subject from environment',NULL,NULL,NULL,8,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(111,0,'color_tone','暖色调','暖调整体色温偏暖约三千五百开尔文，画面以橙黄金杏色为主，人物肤色呈现蜜桃暖粉，头发泛暖棕光泽，融入整体暖色氛围，花田的黄白粉紫野花饱和度偏高，蓝天被压暗偏向青色，黄金时刻加成，温暖如拥抱的治愈浪漫，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/6_08 暖调.jpg',1,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(112,0,'color_tone','冷色调','冷调整体色温偏冷约八千开尔文，画面以蓝青紫银为主，人物肤色在冷调中呈现瓷白微蓝，头发偏冷棕，衣服偏冷粉近乎淡紫，花田绿色偏青蓝野花粉偏冷紫蓝天饱和度极高，冷静孤独的美丽，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/6_09 冷调.jpg',2,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(113,0,'color_tone','高饱和度','高饱和色彩饱和度提高约百分之四十一切色彩被放大，人物肤色饱满蜜桃色，蓝天浓烈钴蓝花田如倾倒的调色盘，黄金时刻加成，浓烈生命力的活力感，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/7_03 高饱和.jpg',3,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(114,0,'color_tone','去饱和','去饱和色彩饱和度降低约百分之七十，花田野花变成灰粉灰紫灰黄像褪色旧照片，人物肤色失去暖粉变得接近灰白，头发失去光泽，只有天空保留一丝蓝，褪色记忆的压抑与时光流逝感，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/7_02 去饱和.jpg',4,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(122,0,'lighting','逆光','逆光轮廓光从人物正后方照射，人物站在野花草甸中整个人被一圈金色光芒勾勒，每一缕发丝边缘都变成发光金丝，衣服边缘透明发光，面部处于柔和剪影中但辅光保留了五官隐约可见，黄金时刻强烈逆光，发光的天使感，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/4_07逆光 : 轮廓光.jpg',2,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(123,0,'lighting','侧光','侧光从正右方九十度照射，面部被精确分为两半右半在金色光芒中左半在深色阴影里鼻梁成为光与影的分界线，人物站在野花草甸中，头发左右明暗分明，衣服一侧亮一侧暗，黄金时刻侧光，半明半暗的戏剧张力，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/5_02 侧光.jpg',3,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(124,0,'lighting','顶光','顶光从正上方照射，眼眶下方有柔和阴影眼窝变深邃颧骨下方有阴影锁骨窝变深头顶和肩膀被照亮，人物站在野花草甸中，软光化解了顶光的压迫感反带神圣意味，表情温柔平和，正午天光的仪式感，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/4_09 顶光.jpg',4,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(125,0,'lighting','底光','底光从下方照射模拟花田地面反射的暖金色光线，面部光影倒置下颌下方被照亮额头反而偏暗但不是恐怖而是奇幻——花田本身在发光映照人物的面庞，表情带着神秘的微笑，黄金时刻地面反光，花田发光的奇幻感，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/5_01底光.jpg',5,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(128,0,'lighting','环境光','环境光仅靠自然散射光——天空蓝色散射加花田暖色反射加云层白色漫射，无明确主光源方向整体曝光偏暗但均匀，人物站在野花草甸中，色彩偏冷但花田暖反射在肤色上留下淡淡暖调，最自然零人工的纯天然感，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/5_04 环境光.jpg',8,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(129,0,'lighting','黄金时刻','黄金时刻日落前约一小时暖金色光线角度低约二十度色温暖金，一切被镀上金色——人物肤色变成蜜色，衣服变成暖金色，野花花瓣半透明泛光长阴影拖在身后，花田和林带都笼罩在金色光雾中，最美的光的浪漫治愈，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/5_09 黄金时刻.jpg',9,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(130,0,'lighting','蓝调时刻','蓝色时刻日落后约二十分钟深蓝暮光色温偏冷，天空深邃钴蓝渐变靠近地平线有一丝暖橙余晖，人物站在野花草甸中肤色在冷光下白皙如月光，衣服在蓝调中偏冷粉，花田色彩降饱和变暗绿暗紫，蓝色时刻的孤独诗意，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/6_01 蓝色时刻.jpg',10,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(131,0,'lighting','硬光','硬光强烈直射阳光无漫射，阴影边缘锐利清晰，人物站在野花草甸中，面部一侧明亮一侧有清晰鼻影锁骨下深色阴影线，野花有轮廓分明的影子，高对比度光比约六比一，正午强光感，戏剧张力强，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/4_02 硬光.jpg',11,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(132,0,'lighting','柔光','软光柔和漫射光，面部无硬阴影鼻梁下只有最淡的过渡影，人物站在野花草甸中，皮肤呈现柔滑瓷器质感肤色均匀，花田整体被均匀照亮低对比度光比约二比一，温柔唯美的偶像剧质感，照片级真实',NULL,NULL,'/aid/storyboard/img/2026/06/07/4_03 软光.jpg',12,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(133,0,'exposure_blur','长曝光','long exposure, motion blur trails, light streaks, smooth water surface',NULL,NULL,NULL,1,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(134,0,'exposure_blur','浅景深虚化','shallow depth of field, strong bokeh, blurred background, subject isolation',NULL,NULL,NULL,2,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(135,0,'exposure_blur','深景深','deep depth of field, everything in focus, sharp from foreground to background',NULL,NULL,NULL,3,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(136,0,'exposure_blur','微距摄影','macro photography, extreme close-up detail, shallow DOF, tiny subject magnified',NULL,NULL,NULL,4,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(137,0,'exposure_blur','移轴效果','tilt-shift effect, miniature world look, selective focus plane, toy-like scene',NULL,NULL,NULL,5,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(138,0,'exposure_blur','双重曝光','double exposure, two images overlaid, ghostly blend, artistic composite',NULL,NULL,NULL,6,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(139,0,'exposure_blur','运动模糊','motion blur, sense of speed and movement, dynamic action frozen partially',NULL,NULL,NULL,7,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(140,0,'exposure_blur','光斑散景','bokeh effect, beautiful out-of-focus light circles, dreamy background',NULL,NULL,NULL,8,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(141,0,'camera_movement','固定机位','固定机位低角度仰拍，人物面带微笑，简洁背景，风格清新自然。站在开满野花的草地上，侧身回头看向镜头，正缓慢优雅地在原地转身，露出灿烂治愈的笑容，风吹动发丝，眼神清澈自然，低角度仰拍，浅景深虚化，前景花丛自然虚化，夏日黄金时段的柔和自然光，通透干净的蓝天，飘着几缕轻薄白云，地平线处是茂密的深绿色林带，色彩鲜活自然，治愈松弛的氛围，自由随性的情绪，大师级作品，最高画质，超精细细节，照片级真实感，电影级人像摄影，轻微胶片颗粒感，索尼A7R4拍摄，50mm F1.4镜头，无声视频，不需要声音','static camera, locked-off shot, no camera movement, stable composition',NULL,'/aid/storyboard/img/2026/06/07/固定机位.mp4',1,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(142,0,'camera_movement','跟拍','低角度跟拍镜头，人物面带微笑，简洁背景，风格清新自然。在开满野花的草地上缓步前行，不时回眸看向镜头，表情宁静淡然，低角度仰拍，浅景深虚化，前景花丛自然虚化，夏日黄金时段的柔和自然光，通透干净的蓝天，飘着几缕轻薄白云，地平线处是茂密的深绿色林带，色彩鲜活自然，治愈松弛的氛围，自由随性的情绪，大师级作品，最高画质，超精细细节，照片级真实感，电影级人像摄影，轻微胶片颗粒感，索尼A7R4拍摄，50mm F1.4镜头，人在前面走，镜头在后面拍','tracking shot, camera follows subject movement, smooth lateral follow',NULL,'/aid/storyboard/img/2026/06/07/跟拍.mp4',2,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(143,0,'camera_movement','环绕','人物面带微笑，简洁背景，风格清新自然。在开满野花的草地上目视前方，露出治愈般的笑容，摄像机围绕人物做平滑的360度弧线环绕运动，环绕一圈，从左侧开始，经过正面，再到右侧，最后到背面，环绕过程中摄像机和人物之间的距离不变。浅景深虚化，前景花丛自然虚化，夏日黄金时段的柔和自然光，通透干净的蓝天，飘着几缕轻薄白云，地平线处是茂密的深绿色林带，色彩鲜活自然，治愈松弛的氛围，自由随性的情绪，大师级作品，最高画质，超精细细节，照片级真实感，电影级人像摄影，轻微胶片颗粒感，索尼A7R4拍摄，50mm F1.4镜头','orbit shot, camera circles around subject, 360 degree rotation',NULL,'/aid/storyboard/img/2026/06/07/环绕.mp4',3,'0','0','2026-03-31 22:27:28','system','2026-03-31 22:27:28','system',NULL),(144,0,'camera_movement','变焦拉近','平滑的电影感变焦推进镜头，摄像机匀速向前推进，拍摄一位站在阳光花田中的人物。面带微笑，周围是开满野花的草地，简洁背景，风格清新自然。浅景深虚化，前景花丛自然虚化，夏日黄金时段的柔和自然光，通透干净的蓝天，飘着几缕轻薄白云，地平线处是茂密的深绿色林带，色彩鲜活自然，治愈松弛的氛围，镜头从中景全身开始，平滑变焦推近至半身近景。运动缓慢稳定、连续流畅。大师级作品，最高画质，超精细细节，照片级真实感，电影级人像摄影，轻微胶片颗粒感，索尼A7R4拍摄，50mm F1.4镜头','zoom in, push in, gradually closer to subject, increasing intimacy',NULL,'/aid/storyboard/img/2026/06/07/变焦拉近.mp4',4,'0','0','2026-03-31 22:27:28