--
-- Table structure for table `aid_provider_error_rule`
--

DROP TABLE IF EXISTS `aid_provider_error_rule`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `aid_provider_error_rule` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键 ID',
  `provider_code` varchar(64) DEFAULT NULL COMMENT '厂商编码（NULL 表示全局规则）',
  `model_code` varchar(128) DEFAULT NULL COMMENT '模型编码（NULL 表示厂商所有模型）',
  `rule_name` varchar(128) NOT NULL COMMENT '规则名称（运营可读）',
  `match_type` varchar(32) NOT NULL COMMENT '匹配类型：HTTP_STATUS/CODE/KEYWORD/REGEX/JSON_PATH',
  `match_pattern` text NOT NULL COMMENT '匹配内容（CODE/KEYWORD 用逗号分隔；HTTP_STATUS 支持 401,500-504）',
  `match_field` varchar(64) DEFAULT NULL COMMENT 'JSON_PATH 模式下的字段路径，如 $.error.code',
  `case_sensitive` tinyint(1) DEFAULT '0' COMMENT '是否区分大小写（0 否 1 是）',
  `error_code` varchar(64) NOT NULL COMMENT '映射到的 TaskErrorCode 枚举名',
  `user_message` varchar(255) DEFAULT NULL COMMENT '覆盖默认 userMessage（NULL 用枚举默认值）',
  `priority` int(11) DEFAULT '100' COMMENT '优先级，数字越小越先匹配',
  `enabled` tinyint(1) DEFAULT '1' COMMENT '启用 (0 禁 1 启)',
  `is_builtin` tinyint(1) DEFAULT '0' COMMENT '内置规则 (1 内置不可删除，只能禁用)',
  `remark` varchar(500) DEFAULT NULL COMMENT '备注',
  `create_by` varchar(64) DEFAULT '' COMMENT '创建者',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) DEFAULT '' COMMENT '更新者',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `idx_provider` (`provider_code`,`enabled`,`priority`) USING BTREE,
  KEY `idx_model` (`model_code`,`enabled`,`priority`) USING BTREE,
  KEY `idx_error_code` (`error_code`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=77 DEFAULT CHARSET=utf8mb4 COMMENT='上游错误归一化规则';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `aid_provider_error_rule`
--

