--
-- Table structure for table `aid_recharge_package`
--

DROP TABLE IF EXISTS `aid_recharge_package`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `aid_recharge_package` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `package_name` varchar(100) NOT NULL COMMENT '套餐名称',
  `credits` decimal(10,2) NOT NULL COMMENT '获得积分',
  `original_price` decimal(10,2) NOT NULL COMMENT '原价(元)',
  `discount` decimal(3,2) DEFAULT '1.00' COMMENT '折扣(0.90表示9折, 1.00表示无折扣)',
  `pay_price` decimal(10,2) NOT NULL COMMENT '实付金额(元, original_price * discount)',
  `icon` varchar(255) DEFAULT NULL COMMENT '图标',
  `description` varchar(500) DEFAULT NULL COMMENT '描述',
