INSERT INTO `sys_job` VALUES (5,'图片视频生成队列','DEFAULT','mediaTask.dispatch','1','0 * * * * ?','1','1','0','admin','2026-03-31 19:58:05','system','2026-07-12 00:29:34',''),(6,'媒体OSS持久化补偿','DEFAULT','mediaTask.ossCompensate()','1','0 0/5 * * * ?','3','1','0','admin','2026-04-24 17:14:26','system','2026-07-12 00:29:34','扫描 aid_media_task 中 status=SUCCEEDED 且 oss_url 为空的记录，重试下载上游产物并按 uploadMode 落地。'),(7,'提取僵尸任务自愈','DEFAULT','extractZombieReclaimTask.reclaim(20, 50)','1','0 */5 * * * ?','3','1','0','system','2026-05-15 23:36:50','system','2026-07-12 00:29:34','CX6: 扫描 aid_extract_task 中 PENDING/PROCESSING 超 20 分钟的任务，自动标记失败 + 退冻结 + 释放 Redis 锁。状态 1=暂停，确认正常后到后台改为 0=正常运行。'),(8,'日志归档(操作/登录)','DEFAULT','logArchiveTask.archive(10)','2','0 30 3 * * ?','3','1','0','','2026-06-28 15:09:34','',NULL,'需求6：DB仅保留最近10天日志，其余归档到本地文件(2MB滚动)'),(9,'任务队列调度拍','SYSTEM','systemCoreTask.queueDispatchTick','1','0/2 * * * * ?','3','1','0','system','2026-07-12 00:29:34','',NULL,'驱动提取任务排队放行与并发名额回收。停用后用户任务将永久排队'),(10,'任务执行租约心跳','SYSTEM','systemCoreTask.leaseHeartbeat','1','0/30 * * * * ?','3','1','0','system','2026-07-12 00:29:34','',NULL,'为执行中任务续 Redis 租约（TTL 90秒），间隔不得超过30秒，否则长任务会被误判失败并退款'),(11,'租约失活僵尸任务回收','SYSTEM','systemCoreTask.reapLeaselessProcessing','1','0/30 * * * * ?','3','1','0','system','2026-07-12 00:29:34','',NULL,'回收进程崩溃后租约失活的 PROCESSING 僵尸任务并退款，停用后用户会被【处理中】永久卡住'),(12,'支付订单兜底查单','SYSTEM','payOrderTask.syncPendingExpiredOrders','1','0 0/2 * * * ?','3','1','0','system','2026-07-12 00:29:34','',NULL,'扫描超时待支付订单并向支付渠道查单，回调丢失时补入账或关单，停用会导致用户已付款不到账'),(13,'媒体计费补偿','SYSTEM','mediaTask.billingCompensate()','1','0 0/2 * * * ?','3','1','0','system','2026-07-12 00:29:34','',NULL,'推进卡在 SETTLING/REFUNDING/FROZEN 的媒体计费到终态，停用会导致用户余额冻结不释放'),(14,'媒体TOKEN追补','SYSTEM','mediaTask.extraChargeCompensate()','1','0 0/5 * * * ?','3','1','0','system','2026-07-12 00:29:34','',NULL,'扫描部分扣费(PARTIAL_DONE)的媒体任务，从可用余额追补差额，保证账目一致'),(15,'提取计费补偿','SYSTEM','extractBillingTask.compensate()','1','0 0/2 * * * ?','3','1','0','system','2026-07-12 00:29:34','',NULL,'推进卡在 SETTLING/REFUNDING/FROZEN 的提取任务计费到终态，停用会导致冻结资金不释放'),(16,'提取TOKEN追补','SYSTEM','extractBillingTask.extraChargeCompensate()','1','0 0/5 * * * ?','3','1','0','system','2026-07-12 00:29:34','',NULL,'扫描部分扣费(PARTIAL_SUCCESS)的提取任务，从可用余额追补差额，保证账目一致'),(17,'图片审查日志清理','SYSTEM','moderationLogTask.cleanExpired()','2','0 30 3 * * ?','3','1','0','system','2026-07-12 00:29:34','',NULL,'每日清理超过保留天数的图片审查日志，防止日志表无限增长'),(18,'媒体补偿轮询(降级备用)','SYSTEM','mediaTask.compensate()','2','0 0/5 * * * ?','3','1','1','system','2026-07-12 00:29:34','',NULL,'旧版补偿轮询，仅作为统一调度中心失效时的降级手段，平时保持暂停'),(19,'模型健康统计归档','SYSTEM','modelHealthTask.archive(30)','2','0 40 3 * * ?','3','1','0','system','2026-07-15 20:05:20','',NULL,'每日把超过保留天数的模型健康统计导出为本地txt存档后删除，保持统计表体量恒定');
